css_template:
#{{ID}} .rep-bottom-bar {
    position: absolute;
    top: 0;
    left: 0;
    width: var(--v-width, 90%);
    box-sizing: border-box;
    min-height: var(--v-height, 60px);
    background: {{PRIMARY_BG}};
    display: flex;
    align-items: center;
    overflow: hidden;
    font-family: '{{FONT_FAMILY}}', 'Roboto Condensed', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform-origin: left center;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
}
#{{ID}} .ticker-track {
    display: flex;
    align-items: center;
    white-space: nowrap;
    padding-left: 100%;
}
#{{ID}} .ticker-item {
    color: {{TITLE_COLOR}};
    font-size: {{FONT_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: uppercase;
    padding: {{PADDING_Y}}px 20px;
}
#{{ID}} .ticker-sep {
    {{SEPARATOR_CSS}}
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-bottom-bar");
    const tickerTrack = root.querySelector(".ticker-track");
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) tl.add(textTl, {{{TEXT_ANIM_SYNC}}} ? ">-0.1" : 0);
        if (tickerTrack) {
            tl.add(() => {
                const trackWidth = tickerTrack.scrollWidth || 0;
                const speedPxPerSec = (parseFloat("{{speed}}") || parseFloat("{{TICKER_SPEED}}") || 50);
                if (speedPxPerSec > 0 && trackWidth > 0) {
                    const duration = trackWidth / speedPxPerSec;
                    gsap.to(tickerTrack, {
                        x: -trackWidth,
                        duration: duration,
                        ease: 'none',
                        repeat: -1
                    });
                }
            });
        }
        return tl;
    };
    root.__slt_hide = () => {
        gsap.killTweensOf(tickerTrack);
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        if (textTl) {
            const sync = {{{TEXT_ANIM_OUT_SYNC}}};
            if (sync) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
})();
